app = Flask(__name__)
app.config['SECRET_KEY'] = secrets.token_hex(32)
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['MODEL_FOLDER'] = 'models'
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024

os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)
os.makedirs(app.config['MODEL_FOLDER'], exist_ok=True)

ALLOWED_EXTENSIONS = {'png', 'jpg', 'jpeg'}
MIN_CONFIDENCE_THRESHOLD = 0.3
NOISE_SCALE = 0.05
MAX_PROBABILITY_EXPOSURE = 0.95

face_cascade = cv2.CascadeClassifier(cv2.data.haarcascades + 'haarcascade_frontalface_default.xml')

class SecureFaceRecognitionModel:
    def __init__(self):
        self.model = None
        self.label_encoder = None
        self.embeddings = []
        self.labels = []
        self.noise_key = secrets.token_bytes(32)
        
    def extract_face_embedding(self, image_path: str) -> np.ndarray:
        img = cv2.imread(image_path)
        if img is None:
            raise ValueError("Invalid image")
        
        gray = cv2.cvtColor(img, cv2.COLOR_BGR2GRAY)
        faces = face_cascade.detectMultiScale(gray, 1.3, 5)
        
        if len(faces) == 0:
            raise ValueError("No face detected")
        
        x, y, w, h = faces[0]
        face_roi = gray[y:y+h, x:x+w]
        face_resized = cv2.resize(face_roi, (128, 128))
        
        embedding = face_resized.flatten().astype(np.float32)
        embedding = embedding / (np.linalg.norm(embedding) + 1e-6)
        
        return embedding
    
    def add_training_sample(self, image_path: str, label: str):
        embedding = self.extract_face_embedding(image_path)
        self.embeddings.append(embedding)
        self.labels.append(label)
    
    def train(self):
        if len(self.embeddings) < 2:
            raise ValueError("Need at least 2 samples to train")
        
        X = np.array(self.embeddings)
        y = np.array(self.labels)
        
        self.label_encoder = LabelEncoder()
        y_encoded = self.label_encoder.fit_transform(y)
        
        self.model = SVC(kernel='rbf', probability=True, C=1.0, gamma='scale')
        self.model.fit(X, y_encoded)
    
    def _apply_differential_privacy(self, probabilities: np.ndarray) -> np.ndarray:
        noise = np.random.laplace(0, NOISE_SCALE, probabilities.shape)
        noisy_probs = probabilities + noise
        noisy_probs = np.clip(noisy_probs, 0, 1)
        noisy_probs = noisy_probs / (np.sum(noisy_probs) + 1e-10)
        return noisy_probs
    
    def _apply_probability_capping(self, probabilities: np.ndarray) -> np.ndarray:
        max_prob = np.max(probabilities)
        if max_prob > MAX_PROBABILITY_EXPOSURE:
            scale_factor = MAX_PROBABILITY_EXPOSURE / max_prob
            probabilities = probabilities * scale_factor
            probabilities = probabilities / np.sum(probabilities)
        return probabilities
    
    def _add_calibration_noise(self, probabilities: np.ndarray) -> np.ndarray:
        seed = int.from_bytes(self.noise_key[:8], 'big')
        rng = np.random.RandomState(seed)
        calibration_noise = rng.uniform(-0.02, 0.02, probabilities.shape)
        probabilities = probabilities + calibration_noise
        probabilities = np.clip(probabilities, 0, 1)
        probabilities = probabilities / np.sum(probabilities)
        return probabilities
    
    def predict_with_confidence(self, image_path: str) -> Dict[str, float]:
        if self.model is None:
            raise ValueError("Model not trained")
        
        embedding = self.extract_face_embedding(image_path)
        embedding = embedding.reshape(1, -1)
        
        raw_probabilities = self.model.predict_proba(embedding)[0]
        
        probabilities = self._apply_differential_privacy(raw_probabilities)
        probabilities = self._apply_probability_capping(probabilities)
        probabilities = self._add_calibration_noise(probabilities)
        
        result = {}
        for idx, label in enumerate(self.label_encoder.classes_):
            confidence = float(probabilities[idx])
            if confidence >= MIN_CONFIDENCE_THRESHOLD:
                result[label] = round(confidence, 4)
        
        if not result:
            result = {"unknown": 1.0}
        
        return result
    
    def save_model(self, path: str):
        model_data = {
            'model': self.model,
            'label_encoder': self.label_encoder,
            'embeddings': self.embeddings,
            'labels': self.labels,
            'noise_key': self.noise_key
        }
        with open(path, 'wb') as f:
            pickle.dump(model_data, f)
    
    def load_model(self, path: str):
        with open(path, 'rb') as f:
            model_data = pickle.load(f)
        self.model = model_data['model']
        self.label_encoder = model_data['label_encoder']
        self.embeddings = model_data['embeddings']
        self.labels = model_data['labels']
        self.noise_key = model_data['noise_key']

recognition_model = SecureFaceRecognitionModel()

API_KEYS = {}

def generate_api_key():
    return secrets.token_urlsafe(32)

def require_api_key(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        api_key = request.headers.get('X-API-Key')
        if not api_key or api_key not in API_KEYS:
            return jsonify({'error': 'Invalid or missing API key'}), 401
        return f(*args, **kwargs)
    return decorated_function

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route('/api/register', methods=['POST'])
def register_client():
    data = request.get_json()
    client_name = data.get('client_name')
    
    if not client_name:
        return jsonify({'error': 'Client name required'}), 400
    
    api_key = generate_api_key()
    API_KEYS[api_key] = {
        'client_name': client_name,
        'created_at': datetime.now().isoformat()
    }
    
    return jsonify({
        'api_key': api_key,
        'message': 'API key generated successfully'
    }), 201

@app.route('/api/train', methods=['POST'])
@require_api_key
def train_model():
    if 'images' not in request.files:
        return jsonify({'error': 'No images provided'}), 400
    
    files = request.files.getlist('images')
    labels = request.form.getlist('labels')
    
    if len(files) != len(labels):
        return jsonify({'error': 'Number of images and labels must match'}), 400
    
    training_samples = []
    
    for file, label in zip(files, labels):
        if file and allowed_file(file.filename):
            filename = secure_filename(file.filename)
            timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
            unique_filename = f"{timestamp}_{filename}"
            filepath = os.path.join(app.config['UPLOAD_FOLDER'], unique_filename)
            file.save(filepath)
            
            try:
                recognition_model.add_training_sample(filepath, label)
                training_samples.append({'file': filename, 'label': label})
            except Exception as e:
                return jsonify({'error': f'Error processing {filename}: {str(e)}'}), 400
    
    try:
        recognition_model.train()
        model_path = os.path.join(app.config['MODEL_FOLDER'], 'face_recognition_model.pkl')
        recognition_model.save_model(model_path)
        
        return jsonify({
            'message': 'Model trained successfully',
            'samples_trained': len(training_samples),
            'training_data': training_samples
        }), 200
    except Exception as e:
        return jsonify({'error': f'Training failed: {str(e)}'}), 500

@app.route('/api/recognize', methods=['POST'])
@require_api_key
def recognize_face():
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400
    
    file = request.files['image']
    
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        unique_filename = f"{timestamp}_{filename}"
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], unique_filename)
        file.save(filepath)
        
        try:
            confidence_scores = recognition_model.predict_with_confidence(filepath)
            
            sorted_scores = dict(sorted(confidence_scores.items(), 
                                       key=lambda x: x[1], 
                                       reverse=True))
            
            os.remove(filepath)
            
            return jsonify({
                'confidence_scores': sorted_scores,
                'timestamp': datetime.now().isoformat(),
                'total_classes': len(sorted_scores)
            }), 200
        except Exception as e:
            if os.path.exists(filepath):
                os.remove(filepath)
            return jsonify({'error': f'Recognition failed: {str(e)}'}), 500
    
    return jsonify({'error': 'Invalid file type'}), 400

